head.script:
scwin.userInfo = $c.data.getMemInfo();

scwin.tr_save_action = "";
scwin.cvNNew = false;   // 신규
scwin.cvUpdate = false; // 수정

scwin.cntWorkUnit = 0;
scwin.cntComUnit  = 0;
scwin.isDelete = false;
scwin.isFocusOut = false;

scwin.onpageload = function() {
    dma_work_unit_re.set("useYn", 1);

    // 공통코드 설정
    let codeOptions = [
        { grpCd: "ZZ205", compID: "lc_homeClsCd, acb_d_homeClsCd", opt :{"range" : "1,EQ"} },
        { grpCd: "EQ005", compID: "lc_catCd, acb_d_catCd" }
    ];
    $c.data.setCommonCode(codeOptions);

    // 버튼 비활성화
    $c.gus.cfDisableBtn([btn_init, btn_add, btn_cancel, btn_save, btn_del]);
};

/**
 * UDC onload
 */
scwin.onUdcCompleted = function () {
    scwin.f_disabledGrdBtn(true); // 그리드 버튼 disable
};

/**
 * data onload
 */
scwin.ondataload = function () {
    // 세션 정보 바인딩
    lc_homeClsCd.setSelectedIndex(0);
    acb_d_homeClsCd.setValue(lc_homeClsCd.getValue());  // 정비소속구분코드

    lc_catCd.setSelectedIndex(0);
    acb_d_catCd.setSelectedIndex(0);
};

/**
 * [조회]
 */
scwin.f_Retrieve = async function() {
    let e = await $c.sbm.execute(sbm_retrieve);
    scwin.sbm_retrieve_submitdone(e);

    // Grid Enable/Disable
    gr_work_pl.setDisabled(false);
    gr_work_part_pl.setReadOnly(true);
    gr_com_part_pl.setReadOnly(true);

    $c.gus.cfDisableKeyData();

    if (ds_work_unit.getRowCount() == 0) {
        acb_d_homeClsCd.setValue(lc_homeClsCd.getValue()); // 정비소속구분코드
        $c.gus.cfDisableBtn([btn_add, btn_cancel, btn_save, btn_del]);
    } else {
        $c.gus.cfDisableBtn([btn_cancel, btn_save]);
    }
    scwin.f_disabledGrdBtn(true); // 그리드 버튼 disable
};

/**
 * 상세 조회
 */
scwin.f_Retrieve_detail = async function(fixWorkUnitNumber) {
    sbm_retrieve_detail.action = "/ps.eq.opinfomgnt.opinfomgnt.RetrieveFixWorkUnitDetailCMD.do?fixWorkUnitNumber="+fixWorkUnitNumber+"&homeClsCd="+acb_d_homeClsCd.getValue();
    let e = await $c.sbm.execute(sbm_retrieve_detail);
    scwin.sbm_retrieve_detail_submitdone(e);
};

/**
 * 장비모델별 부품 [행추가]
 */
scwin.f_AddPartRow = async function() {
    if (scwin.cvUpdate == true || scwin.cvNNew == true) {
        // Mandatory 항목이 누락하지 않았는지 체크한다.
        let ret = await $c.gus.cfValidate([ed_d_fixWrkUnitNo, ed_fixWrkUnitNm]);
        if (!ret) return;

        if(ed_d_fixWrkUnitNo.getValue().length < 6){
            await $c.win.alert("작업단위코드은(는) 6자리수만큼 입력하십시오");
            ed_d_fixWrkUnitNo.focus();
            return;
        }
        if (scwin.cvUpdate == true)
            scwin.tr_save_action = "/ps.eq.opinfomgnt.opinfomgnt.UpdateFixWorkUnitCMD.do";
        else if (scwin.cvNNew == true)
            scwin.tr_save_action = "/ps.eq.opinfomgnt.opinfomgnt.RegistFixWorkUnitCMD.do";

        let newRow = ds_work_unit_list.insertRow();

        gr_work_part_pl.setFocusedCell(newRow, "eqModelCd");
        ds_work_unit_list.setCellData(newRow, "fixWrkUnitNo", ed_d_fixWrkUnitNo.getValue());
        ds_work_unit_list.setCellData(newRow, "homeClsCd", acb_d_homeClsCd.getValue());
        ds_work_unit_list.setCellData(newRow, "useExpectQty", "0");
    }
};

/**
 * 공통 부품 [행추가]
 */
scwin.f_AddComPartRow = async function() {
    if (scwin.cvUpdate == true || scwin.cvNNew == true) {
        // Mandatory 항목이 누락하지 않았는지 체크한다.
        let ret = await $c.gus.cfValidate([ed_d_fixWrkUnitNo, ed_fixWrkUnitNm]);
        if (!ret) return;

        if(ed_d_fixWrkUnitNo.getValue().length < 6){
            await $c.win.alert("작업단위코드은(는) 6자리수만큼 입력하십시오");
            ed_d_fixWrkUnitNo.focus();
            return;
        }

        if (scwin.cvUpdate == true)
            scwin.tr_save_action = "/ps.eq.opinfomgnt.opinfomgnt.UpdateFixWorkUnitCMD.do";
        else if (scwin.cvNNew == true)
            scwin.tr_save_action = "/ps.eq.opinfomgnt.opinfomgnt.RegistFixWorkUnitCMD.do";

        let newRow = ds_com_unit_list.insertRow();

        gr_com_part_pl.setFocusedCell(newRow, "partCd");
        ds_com_unit_list.setCellData(newRow, "fixWrkUnitNo", ed_d_fixWrkUnitNo.getValue());
        ds_com_unit_list.setCellData(newRow, "homeClsCd", lc_homeClsCd.getValue());
        ds_com_unit_list.setCellData(newRow, "useExpectQty", "0");
    }
};

/**
 * [신규]
 */
scwin.f_Create = async function() {
    scwin.tr_save_action = "/ps.eq.opinfomgnt.opinfomgnt.RegistFixWorkUnitCMD.do";
    scwin.cvNNew = true;

    $c.gus.cfEnableKeyData();
    $c.gus.cfEnableAllBtn();
    $c.gus.cfDisableBtn([btn_init, btn_add, btn_del]); // 버튼관련
    scwin.f_disabledGrdBtn(false); // 그리드 버튼 enable

    if (ds_work_unit.getRowCount() > 0) {
        let newRow = ds_work_unit.insertRow();
        gr_work_pl.setFocusedCell(newRow, "fixWrkUnitNo");

        // work unit 초기화
        ds_work_unit.setCellData(newRow, "homeClsCd", lc_homeClsCd.getValue()); // 정비소속구분코드
        ds_work_unit.setCellData(newRow, "catCd", "01");
        ds_work_unit.setCellData(newRow, "useYn", 1);
        ds_work_unit.setCellData(newRow, "stndWrkHhCnt", "0");
    } else {
        let newRow = ds_work_unit.insertRow(); 
        gr_work_pl.setFocusedCell(newRow, "fixWrkUnitNo");

        ds_work_unit.setCellData(newRow, "homeClsCd", lc_homeClsCd.getValue()); // 정비소속구분코드
        ds_work_unit.setCellData(newRow, "fixWrkUnitNo", "");
        ds_work_unit.setCellData(newRow, "fixWrkUnitNm", "");
        ds_work_unit.setCellData(newRow, "catCd", "01");
        ds_work_unit.setCellData(newRow, "useYn", 1);
        ds_work_unit.setCellData(newRow, "stndWrkHhCnt", "0"); 
    }

    acb_d_homeClsCd.setValue(ds_work_unit.getCellData(0, "homeClsCd"));
    acb_d_catCd.setSelectedIndex(0);

    // detail list 2개를 초기화 시킨다.
    scwin.f_Retrieve_detail("0");

    gr_work_pl.setDisabled(true);
    gr_work_part_pl.setReadOnly(false);
    gr_com_part_pl.setReadOnly(false);

    ed_d_fixWrkUnitNo.focus();
};

/**
 * [수정]
 */
scwin.f_Update = async function() {
    scwin.tr_save_action = "/ps.eq.opinfomgnt.opinfomgnt.UpdateFixWorkUnitCMD.do";
    scwin.cvUpdate = true;

    // Grid Enable/Disable
    gr_work_pl.setDisabled(true);
    gr_work_part_pl.setReadOnly(false);
    gr_com_part_pl.setReadOnly(false);

    $c.gus.cfEnableKeyData();

    $c.gus.cfDisableKey();

    $c.gus.cfDisableBtn([btn_add, btn_del]);

    scwin.f_disabledGrdBtn(false); // 그리드 버튼 enable
};

/**
 * [취소]
 */
scwin.f_Cancel = async function() {
    if (ds_work_unit.getRowCount() > 0) {
        $c.gus.cfDisableBtn([btn_cancel, btn_save]);
    } else {
        $c.gus.cfDisableBtn([btn_add, btn_cancel, btn_save, btn_del]);
    }

    scwin.f_disabledGrdBtn(true); // 그리드 버튼 disable

    let curRow = ds_work_unit.getRowPosition();
    let rowStatus = ds_work_unit.getRowStatus(curRow);

    $c.data.undoAll(ds_work_unit);
    $c.data.undoAll(ds_work_unit_list);
    $c.data.undoAll(ds_com_unit_list);

    $c.gus.cfDisableKeyData();

    gr_work_pl.setDisabled(false);
    gr_work_part_pl.setReadOnly(true);
    gr_com_part_pl.setReadOnly(true);

    scwin.cvUpdate = false;
    scwin.cvNNew = false;

    if(rowStatus == "C") {
        gr_work_pl.setFocusedCell(0, "fixWrkUnitNo");
    } else {
        gr_work_pl.setFocusedCell(curRow, "fixWrkUnitNo");
    }
};

/**
 * [저장]
 */
scwin.f_Save = async function() {
    let ret1 = await $c.gus.cfValidate([tb_fixWrkUnit]);
    if (!ret1) return;

	if(ed_d_fixWrkUnitNo.getValue().length < 6){
		await $c.win.alert("작업단위코드은(는) 6자리수만큼 입력하십시오");
		ed_d_fixWrkUnitNo.focus();
		return;
	}

    // 변경한 데이터가 있는지 체크한다. 
    if (ds_work_unit.getModifiedIndex().length == 0 && ds_work_unit_list.getModifiedIndex().length == 0 && ds_com_unit_list.getModifiedIndex().length == 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, "작업단위정보"));
    } else {

        let ret2 = await $c.gus.cfValidate([gr_work_part_pl], null, true);
        if(!ret2) {
            return;
        }
        let ret3 = await $c.gus.cfValidate([gr_com_part_pl], null, true);
        if(!ret3) {
            return;
        }
        if (ret2 && ret3) {
            if (ed_d_stndWrkHhCnt.getValue() < 1) {
                await $c.win.alert($c.data.getMessage(MSG_CM_ERR_013, "표준작업시간", "1"));
                ed_d_stndWrkHhCnt.focus();
                return;
            }

            // 장비모델별 부품의 수량 검사
            for (let row = 0; row < ds_work_unit_list.getRowCount(); row++) {
                if (ds_work_unit_list.getCellData(row, "useExpectQty") < 1) {
                    await $c.win.alert($c.data.getMessage(MSG_CM_ERR_013, "수량", "1"));
                    gr_work_part_pl.setFocusedCell(row, "useExpectQty",true);
                    return;
                }
            }

            // 공통 부품의 수량 검사
            for (let row = 0; row < ds_com_unit_list.getRowCount(); row++) {
                if (ds_com_unit_list.getCellData(row, "useExpectQty") < 1) {
                    await $c.win.alert($c.data.getMessage(MSG_CM_ERR_013, "수량", "1"));
                    gr_com_part_pl.setFocusedCell(row, "useExpectQty",true);
                    return;
                }
            }

            let confirm = await $c.win.confirm("저장하시겠습니까?");

            if (confirm == true) {
                // disable 처리
                $c.gus.cfDisableKeyData();
                $c.gus.cfDisableBtn([btn_cancel, btn_save]); // 버튼 아이디 반영
                btn_cancel.setDisabled(true);
                scwin.f_disabledGrdBtn(true); // 그리드 버튼 disable

                gr_work_pl.setDisabled(false);
                gr_work_part_pl.setReadOnly(true);
                gr_com_part_pl.setReadOnly(true);

                sbm_save.action = scwin.tr_save_action;
                sbm_save.userData1="noError";
                let e = await $c.sbm.execute(sbm_save);
                if(e.responseJSON.resultDataSet[0].Code == -1) { // error

                    await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
                }

                scwin.sbm_save_submitdone(e);

                scwin.f_Retrieve_detail(ds_work_unit.getCellData(gr_work_pl.getFocusedRowIndex(), "fixWrkUnitNo"));
            }
        }
    }
};


/**
 * [삭제]
 */
scwin.f_Delete = async function() {
    let confirm = await $c.win.confirm("삭제하시겠습니까?");

    if (confirm == true) {
        sbm_delete.action = "/ps.eq.opinfomgnt.opinfomgnt.DeleteFixWorkUnitCMD.do"
						+ "?fixWorkUnitNumber=" + ed_d_fixWrkUnitNo.getValue()
						+ "&homeClsCd=" + acb_d_homeClsCd.getValue();

        sbm_delete.userData1 = "noError";
        let e = await $c.sbm.execute(sbm_delete);
        if(e.responseJSON.resultDataSet[0].Code == -1) { // error
            await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        }
        await scwin.sbm_save_submitdone(e);

        await $c.gus.cfDisableKeyData();
	    await $c.gus.cfDisableBtn([btn_save]);


	    scwin.f_Retrieve();
    }
};

/**
 * 조회 조건 지우기
 */
scwin.f_FieldClear = async function() {
    $c.gus.cfInitObjects(tb_wrk,null);
};

//-------------------------------------------------------------------------
// 명칭 조회 Popup 처리 : 그리드에서 입력된 코드정보로 명을 조회
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = async function(disGubun, row, pClose) {
    let pCode = "";
    let pName = "";
    let pWhere = "";

    let pHomeClsCd = acb_d_homeClsCd.getValue();
    if (pHomeClsCd == "LO") {    // 물류 
        pWhere = "LV";  
    } else {    // 고속
        pWhere = "TV";
    }

    scwin.tempGridRow = row;

    switch (disGubun) {
        case 1:
            // 모델 코드팝업          
            pCode = ds_work_unit_list.getCellData(row, "eqModelCd");    // 품명코드
            udc_comCode.setSelectId("retrieveEqModelListInfo");
            await udc_comCode.cfCommonPopUp(scwin.udc_eqModelListInfo_callBackFunc
                                            ,pCode						// 화면에서의 ??? Code Element의	Value
                                            ,pName						// 화면에서의 ??? Name Element의	Value
                                            ,pClose						// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                            ,null						// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                            ,null						// Title순서	
                                            ,null						// 보여주는 각 컬럼들의 폭	
                                            ,null						// 컬럼중에서 숨기는	컬럼 지정	
                                            ,pWhere						// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                            ,null						// POP-UP뛰을때 원도우의	사용자 정의	폭
                                            ,null						// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                            ,null						// 윈도우 위치 Y좌표	
                                            ,null						// 윈도우 위치 X좌표
                                            ,null						// 중복체크여부	("F")
                                            ,"T"						// 전체검색허용여부	("F")
                                            ,"모델정보,모델코드,모델명"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번검색Nm")
                                            ); 
            break;

        case 2:
            // 부품 코드팝업 (장비모델별 부품 그리드)
            pCode = ds_work_unit_list.getCellData(row, "partCd");   // 부품코드
            udc_comCode.setSelectId("retrievePartBasicInfo");
            await udc_comCode.cfCommonPopUp(scwin.udc_partBasicInfo1_callBackFunc
                                    ,pCode						// 화면에서의 ??? Code Element의	Value
									,pName						// 화면에서의 ??? Name Element의	Value
									,pClose						// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
									,null						// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
									,null						// Title순서	
									,null						// 보여주는 각 컬럼들의 폭	
									,null						// 컬럼중에서 숨기는	컬럼 지정	
									,null						// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
									,null						// POP-UP뛰을때 원도우의	사용자 정의	폭
									,null						// POP-UP뛰을때 우도우의	사용자 정의	높이	
									,null						// 윈도우 위치 Y좌표	
									,null						// 윈도우 위치 X좌표
									,null						// 중복체크여부	("F")
									,"F"						// 전체검색허용여부	("F")
									,"부품정보,부품코드,부품명"    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번검색Nm")
                                    );
            break;

        case 3:
            // 부품 코드팝업 (공통 부품 그리드)
            pCode = ds_com_unit_list.getCellData(row, "partCd");    // 부품코드
            udc_comCode.setSelectId("retrievePartBasicInfo");
            await udc_comCode.cfCommonPopUp(scwin.udc_partBasicInfo2_callBackFunc
                                    ,pCode						// 화면에서의 ??? Code Element의	Value
									,pName						// 화면에서의 ??? Name Element의	Value
									,pClose						// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
									,null						// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
									,null						// Title순서	
									,null						// 보여주는 각 컬럼들의 폭	
									,null						// 컬럼중에서 숨기는	컬럼 지정	
									,null						// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
									,null						// POP-UP뛰을때 원도우의	사용자 정의	폭
									,null						// POP-UP뛰을때 우도우의	사용자 정의	높이	
									,null						// 윈도우 위치 Y좌표	
									,null						// 윈도우 위치 X좌표
									,null						// 중복체크여부	("F")
									,"F"						// 전체검색허용여부	("F")
									,"부품정보,부품코드,부품명"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번검색Nm")
									);
            break;
    }
};

scwin.udc_eqModelListInfo_callBackFunc = function(rtnList) {
    let row = scwin.tempGridRow;

    if ( rtnList != null) {
        if(rtnList[0].trim() != "N/A"){
            $c.gus.cfSetGridReturnValue(rtnList, ds_work_unit_list, row, "eqModelCd", "eqModelNm");           
        } else {
            ds_work_unit_list.setCellData(row,"eqModelCd", ""); 
            ds_work_unit_list.setCellData(row,"eqModelNm", "");
        }
    } else {
        ds_work_unit_list.setCellData(row,"eqModelCd", ""); 
        ds_work_unit_list.setCellData(row,"eqModelNm", ""); 
    }
};

scwin.udc_partBasicInfo1_callBackFunc = async function(rtnList) {
    $p.setTimeout(async ()=>{
        let row = scwin.tempGridRow;
        if (rtnList != null && rtnList !== undefined && rtnList[0] != "N/A") {
            for (let i = 0; i < ds_work_unit_list.getRowCount(); i++) {
                if (ds_work_unit_list.getCellData(i, "partCd") == rtnList[0]) {
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_032, ["부품"])
                    gr_work_part_pl.setFocusedCell(row, "partCd", true);
                    return;
                }
            }
            for (let i = 0; i < ds_com_unit_list.getRowCount(); i++) {
                if (ds_com_unit_list.getCellData(i, "partCd") == rtnList[0]) {
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_032, ["부품"])
                    return;
                }
            }

            ds_work_unit_list.setCellData(row, "partCd", rtnList[0]);
            ds_work_unit_list.setCellData(row, "partNm", rtnList[1]);
            ds_work_unit_list.setCellData(row, "partUnitNm", rtnList[3]);
            ds_work_unit_list.setCellData(row, "catNm", rtnList[4]);
            ds_work_unit_list.setCellData(row, "partMakerNm", rtnList[5]);
        } else {
            ds_work_unit_list.setCellData(row, "partCd", "");
        }
    }, 100)    
};

scwin.udc_partBasicInfo2_callBackFunc = async function(rtnList) {
    $p.setTimeout(async ()=>{
        let row = scwin.tempGridRow;
        if (rtnList != null && rtnList !== undefined && rtnList[0] != "N/A") {
            for (let i = 0; i < ds_work_unit_list.getRowCount(); i++) {
                if (ds_work_unit_list.getCellData(i, "partCd") == rtnList[0]) {
                    await $c.win.alert($c.data.getMessage(MSG_CM_ERR_032, "부품"));
                    return;
                }
            }
            for (let i = 0; i < ds_com_unit_list.getRowCount(); i++) {
                if (ds_com_unit_list.getCellData(i, "partCd") == rtnList[0]) {
                    await $c.win.alert($c.data.getMessage(MSG_CM_ERR_032, "부품"));
                    gr_com_part_pl.setFocusedCell(row, "partCd", true);
                    return;
                }
            }

            ds_com_unit_list.setCellData(row, "partCd", rtnList[0]);
            ds_com_unit_list.setCellData(row, "partNm", rtnList[1]);
            ds_com_unit_list.setCellData(row, "partUnitNm", rtnList[3]);
            ds_com_unit_list.setCellData(row, "catNm", rtnList[4]);
            ds_com_unit_list.setCellData(row, "partMakerNm", rtnList[5]);
        } else {
            ds_com_unit_list.setCellData(row, "partCd", "");
        }
    }, 100)
};


//-------------------------------------------------------------------------
// 그리드 row 추가/삭제/취소 버튼 관련
//-------------------------------------------------------------------------
scwin.f_disabledGrdBtn = function(ctrl) {
    let cursor = "";
    if (ctrl) cursor = "default"; // Disable
    else cursor = "pointer";  // Enable

    btnAddrow.setDisabled(ctrl);
    btnDelrow.setDisabled(ctrl);
    btnCanrow.setDisabled(ctrl);
    btnAddrow2.setDisabled(ctrl);
    btnDelrow2.setDisabled(ctrl);
    btnCanrow2.setDisabled(ctrl);

    btnAddrow.setStyle("cursor", cursor);
    btnDelrow.setStyle("cursor", cursor);
    btnCanrow.setStyle("cursor", cursor);
    btnAddrow2.setStyle("cursor", cursor);
    btnDelrow2.setStyle("cursor", cursor);
    btnCanrow2.setStyle("cursor", cursor);
};

/**
 * 조회 콜백
 */
scwin.sbm_retrieve_submitdone = function(e) {
    gr_work_pl.setFocusedCell(0, "fixWrkUnitNo");
    totalRows1.setValue(ds_work_unit.getRowCount());
    scwin.f_Retrieve_detail(ds_work_unit.getCellData(0, "fixWrkUnitNo"));
};

scwin.sbm_retrieve_detail_submitdone = async function(e) {
    scwin.cntWorkUnit = ds_work_unit_list.getRowCount();
    scwin.cntComUnit = ds_com_unit_list.getRowCount();
    gr_work_part_pl.setFocusedCell(0, "eqModelCd");
    gr_com_part_pl.setFocusedCell(0, "partCd");
    totalRows2.setValue(ds_work_unit_list.getRowCount());
    totalRows3.setValue(ds_com_unit_list.getRowCount());
};

/**
 * [저장] callback
 */
scwin.sbm_save_submitdone = async function(e) {
    if(e.responseJSON.resultDataSet[0].Code != -1){
        await $c.win.alert($c.data.getMessage(MSG_CM_INF_001)); // 성공적으로 저장하였습니다
        ds_work_unit.reform();
        ds_work_unit_list.reform();
        ds_com_unit_list.reform();
    } else {
        if(scwin.cvNNew){
            scwin.f_Cancel();
            scwin.f_Create();
	    }
    }
};

scwin.gr_work_pl_onrowindexchange = function (rowIndex, oldRow) {
    let fixWrkUnitNo = ds_work_unit.getCellData(rowIndex, "fixWrkUnitNo");
    scwin.f_Retrieve_detail(fixWrkUnitNo);
};


scwin.gr_work_part_pl_onrowindexchange = function (rowIndex, oldRow) {
    let row = ds_work_unit_list.getRowPosition();
    if (row < scwin.cntWorkUnit)
        gr_work_part_pl.setColumnReadOnly("eqModelCd", true);
    else
        gr_work_part_pl.setColumnReadOnly("eqModelCd", false);
};


scwin.gr_work_part_pl_ontextimageclick = async function (rowIndex, columnIndex) {
    $p.setTimeout(()=> {
        if(scwin.isFocusOut) {
            scwin.isFocusOut = false;
            return;
        } else {
            let colid = gr_work_part_pl.getColumnID(columnIndex);
            switch (colid) {
                case "eqModelCd":
                    scwin.f_openCommPopUpGrid(1, rowIndex, 'F');
                    break;
                case "partCd":
                    scwin.f_openCommPopUpGrid(2, rowIndex, 'F');
                    break;
            } 
        }
    }, 100);    
};

scwin.gr_work_part_pl_onbeforeedit = function (rowIndex, columnIndex, value) {
    scwin.oldData = value;
};

scwin.gr_work_part_pl_onafteredit = function (row, columnIndex, value) {
    let colid = gr_work_part_pl.getColumnID(columnIndex);
    let olddata = scwin.oldData;
    let newdata = value;
    scwin.isFocusOut = true;

    if (row >= 0 && ds_work_unit_list.getRowCount() > row) {
        switch (colid) {
            case "eqModelCd" :
                if (newdata != "" && newdata != olddata) {
                    ds_work_unit_list.setCellData(row, "eqModelNm", "");
                    scwin.f_openCommPopUpGrid(1, row, 'T');
                } else if(newdata == "") {
                    ds_work_unit_list.setCellData(row, "eqModelCd", "");
                    ds_work_unit_list.setCellData(row, "eqModelNm", "");
                    scwin.isFocusOut = false;
                }
                break;

            case "partCd" :
                if (newdata != "" && newdata != olddata) {
                    ds_work_unit_list.setCellData(row, "partNm", "");
                    ds_work_unit_list.setCellData(row, "partUnitNm", "");
                    ds_work_unit_list.setCellData(row, "catNm", "");
                    ds_work_unit_list.setCellData(row, "partMakerNm", "");
                    scwin.f_openCommPopUpGrid(2, row, 'T');
                } else if(newdata == "") {
                    ds_work_unit_list.setCellData(row, "partCd", "");
                    ds_work_unit_list.setCellData(row, "partNm", "");
                    ds_work_unit_list.setCellData(row, "partUnitNm", "");
                    ds_work_unit_list.setCellData(row, "catNm", "");
                    ds_work_unit_list.setCellData(row, "partMakerNm", "");
                    scwin.isFocusOut = false;
                } else if(newdata == olddata) {
                    scwin.isFocusOut = false;
                }
                break;
        }
    }
};

scwin.gr_com_part_pl_onrowindexchange = function (rowIndex, oldRow) {
    let row = ds_com_unit_list.getRowPosition();

    if (row < scwin.cntComUnit)
        gr_com_part_pl.setColumnReadOnly("partCd", true);
    else
        gr_com_part_pl.setColumnReadOnly("partCd", false);
};

